import { Factory, Renderer } from 'https://cdn.jsdelivr.net/npm/vexflow@5/+esm';
const el = document.getElementById('score'); el.style.height = '260px';
const renderer = new Renderer(el, Renderer.Backends.SVG); renderer.resize(720, 260);
const vf = new Factory({ renderer: { elementId: null, width: 720, height: 260 } }).setContext(renderer.getContext());
const score = vf.EasyScore(), notes = data.easyScore ? score.notes(data.easyScore, { clef: data.clef ?? 'treble' }) : [];
vf.System({ x: 10, y: 10, width: 700 }).addStave({ voices: notes.length ? [score.voice(notes, { time: data.time ?? '4/4' })] : [] }).addClef(data.clef ?? 'treble').addTimeSignature(data.time ?? '4/4');
vf.draw();

